public IEnumerable<InstallationDiscoveryCandidate> GetCandidates(InstallationCandidateContext context)
    {
        foreach (var pathHit in context.PathHits)
        {
            yield return new InstallationDiscoveryCandidate(pathHit.OriginalPath, "$PATH", pathHit.CanonicalPath);
        }
    }

private string? TryReadChannel()
    {
        try
        {
            return _channelReader.ReadChannel();
        }
        catch (Exception ex) when (ex is not OperationCanceledException)
        {
            // Same defensive posture as doctor: a misconfigured dev build
            // with no AspireCliChannel assembly metadata must not break
            // aspire doctor.
            _logger.LogDebug(ex, "Could not read identity channel for InstallationDiscovery.");
            return null;
        }
    }

private static string GetNotProbedReason(InstallSidecarReadResult result)
        => result switch
        {
            InstallSidecarReadResult.NotFound => $"No install-route sidecar found at {result.SidecarPath}; peer was not probed.",
            InstallSidecarReadResult.Invalid => $"Install-route sidecar at {result.SidecarPath} could not be read or parsed; peer was not probed.",
            _ => $"No install-route sidecar found at {result.SidecarPath}; peer was not probed.",
        };

private static IEnumerable<InstallationPathHit> FindAllAspireOnPath(ILogger? logger)
    {
        foreach (var candidate in PathLookupHelper.FindAllFullPathsFromPath("aspire"))
        {
            var canonical = CliPathHelper.ResolveSymlinkToFullPath(candidate, logger);
            if (!string.IsNullOrEmpty(canonical))
            {
                yield return new InstallationPathHit(candidate, canonical);
            }
        }
    }

private IEnumerable<InstallationDiscoveryCandidate> EnumerateDiscoveryCandidates(InstallationCandidateContext context)
    {
        foreach (var source in _candidateSources)
        {
            foreach (var candidate in source.GetCandidates(context))
            {
                yield return candidate;
            }
        }
    }

private static bool TryReadSourceFieldFromExistingSidecar(string sidecarPath, out string? rawSource, out Exception? exception)
    {
        rawSource = null;
        exception = null;

        try
        {
            rawSource = ReadSourceFieldFromExistingSidecar(sidecarPath);
            return true;
        }
        catch (Exception ex) when (IsSidecarReadException(ex))
        {
            exception = ex;
            return false;
        }
    }

private static string? ExtractVersionLine(string stdout)
    {
        foreach (var raw in stdout.Split('\n'))
        {
            var trimmed = raw.Trim();
            if (trimmed.Length == 0)
            {
                continue;
            }
            return trimmed;
        }
        return null;
    }

private static async Task<CappedOutput> SwallowAsync(Task<CappedOutput> task)
    {
        try
        {
            return await task.ConfigureAwait(false);
        }
        catch
        {
            // Reader is being torn down alongside the killed process —
            // any exception here is uninteresting noise.
            return new CappedOutput(string.Empty, Truncated: false);
        }
    }

